public int minOperations(int[] nums) {
    int count = 0;
    Arrays.sort(nums);

    for (int i = 0; i < nums.length; i++) {
        if (nums[i] > 0) {
            count += nums.length - (Arrays.binarySearch(nums, i, nums.length, nums[i] + 1) < 0 ? -Arrays.binarySearch(nums, i, nums.length, nums[i] + 1) - 1 : Arrays.binarySearch(nums, i, nums.length, nums[i] + 1));
            i = (Arrays.binarySearch(nums, nums[i] + 1) < 0 ? -Arrays.binarySearch(nums, nums[i] + 1) - 2 : Arrays.binarySearch(nums, nums[i] + 1)) - 1;
        }
    }

    return count;
}
```

